class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        i, j = 0, 0
        while i < len(start) and j < len(result):
            if start[i] == result[j]:
                i += 1
                j += 1
            elif start[i] == 'X' and result[j] == 'X':
                i += 1
                j += 1
            elif start[i] == 'L' and j + 1 < len(result) and result[j + 1] == 'X' and result[j] == 'R':
                j += 2
            elif start[i] == 'R' and i + 1 < len(start) and start[i + 1] == 'X' and start[i] == 'L':
                i += 2
            else:
                return False
        return i == len(start) and j == len(result)
